let cur = 0, scrollTimer = null;

const SLIDE_BG = ['#1a1420','#0d1520','#1a1208','#101510','#18100d','#120d1a'];
const SLIDE_AC = ['#7B5AA0','#3A6A9A','#9A7040','#2A7A4A','#9A3050','#5A6A9A'];

function makeCoverSVG(i) {
const bg = SLIDE_BG[i % SLIDE_BG.length];
const ac = SLIDE_AC[i % SLIDE_AC.length];
const p = projects[i];
const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="1280" height="720"><rect width="1280" height="720" fill="${bg}"/><rect width="1280" height="3" fill="${ac}" opacity="0.7"/><rect y="717" width="1280" height="3" fill="${ac}" opacity="0.2"/><text x="640" y="345" text-anchor="middle" fill="${ac}" opacity="0.1" font-size="120" font-family="Georgia">${p.cat}</text><text x="640" y="400" text-anchor="middle" fill="white" opacity="0.2" font-size="32" font-family="Georgia">${p.title}</text></svg>`;
return 'data:image/svg+xml;base64,' + btoa(unescape(encodeURIComponent(svg)));
}

function makeThumbSVG(pi, t) {
const bg = SLIDE_BG[pi % SLIDE_BG.length];
const ac = SLIDE_AC[pi % SLIDE_AC.length];
const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="400" height="225"><rect width="400" height="225" fill="${bg}"/><rect width="400" height="3" fill="${ac}" opacity="0.6"/><text x="200" y="118" text-anchor="middle" fill="${ac}" opacity="0.3" font-size="14" font-family="monospace">still ${t+1}</text></svg>`;
return 'data:image/svg+xml;base64,' + btoa(unescape(encodeURIComponent(svg)));
}

function buildSwiper() {
const sw = document.getElementById('proj-swiper');
sw.innerHTML = projects.map((p, i) => `
<div class="proj-slide" data-i="${i}" style="opacity:${i===0?1:0.35};transform:scale(${i===0?1:0.97})">
<iframe class="vframe" src="" allow="autoplay; fullscreen; picture-in-picture; xr-spatial-tracking" allowfullscreen webkitallowfullscreen mozallowfullscreen></iframe>
<img class="slide-cover" src="${makeCoverSVG(i)}" alt="${p.title}" />
<img class="still-preview" src="" alt="Still from ${p.title}" />
<div class="play-overlay"><div class="play-overlay-btn"></div></div>
</div>`).join('') + '<div class="swiper-end-spacer"></div>';
sw.addEventListener('scroll', () => {
clearTimeout(scrollTimer);
scrollTimer = setTimeout(detectSnap, 120);
});
loadVimeo(1);
setTimeout(() => navTo(1), 50);
}

function detectSnap() {
const sw = document.getElementById('proj-swiper');
const slides = [...sw.querySelectorAll('.proj-slide')];
const cx = sw.scrollLeft + sw.clientWidth / 2;
let newIdx = 0, minD = Infinity;
slides.forEach((s, i) => {
const d = Math.abs((s.offsetLeft + s.offsetWidth / 2) - cx);
if (d < minD) { minD = d; newIdx = i; }
});
slides.forEach((s, i) => {
s.style.opacity = i === newIdx ? '1' : '0.35';
s.style.transform = i === newIdx ? 'scale(1)' : 'scale(0.97)';
});
if (newIdx !== cur) {
// Stop video on previous slide
const prevSlide = slides[cur];
if (prevSlide) {
const prevFr = prevSlide.querySelector('.vframe');
const prevCov = prevSlide.querySelector('.slide-cover');
const prevOverlay = prevSlide.querySelector('.play-overlay');
if (prevFr) { prevFr.src = ''; prevFr.removeAttribute('data-loaded'); }
if (prevCov) { prevCov.onclick = null; prevCov.removeAttribute('data-poster'); }
if (prevOverlay) prevOverlay.classList.remove('visible');
}
cur = newIdx;
fadeInfo();
loadVimeo(newIdx);
}
updateNav();
}

const warningConfirmed = new Set();

function loadVimeo(i) {
const p = projects[i];
const slide = document.querySelectorAll('.proj-slide')[i];
if (!slide) return;
const fr = slide.querySelector('.vframe');
const cov = slide.querySelector('.slide-cover');
const still = slide.querySelector('.still-preview');
// Show warning modal if project has a warning and not yet confirmed
if (p.warning && !warningConfirmed.has(p.id)) {
const modal = document.getElementById('warning-modal');
document.getElementById('warning-text').textContent = p.warning;
modal.style.display = 'flex';
document.getElementById('warning-cancel').onclick = () => {
modal.style.display = 'none';
navTo(i - 1 >= 0 ? i - 1 : i + 1);
};
document.getElementById('warning-confirm').onclick = () => {
modal.style.display = 'none';
warningConfirmed.add(p.id);
const stillNav = document.getElementById('still-nav');
if (stillNav) stillNav.style.display = 'none';
if (still) { still.style.display = 'none'; still.src = ''; }
if (p.youtubeId) {
fr.src = 'https://www.youtube.com/embed/' + p.youtubeId + '?color=white&modestbranding=1&rel=0';
} else if (p.vimeoId) {
fr.src = 'https://player.vimeo.com/video/' + p.vimeoId + (p.vimeoHash ? '?h=' + p.vimeoHash + '&' : '?') + 'color=ff6600&title=0&byline=0&portrait=0&fullscreen=1&playsinline=0' + (p.vimeoStart ? '#t=' + p.vimeoStart + 's' : '');
}
fr.style.display = 'block';
fr.setAttribute('data-loaded', '1');
cov.style.display = 'none';
};
return;
}
_doLoadVimeo(p, slide, fr, cov);
}

function _doLoadVimeo(p, slide, fr, cov) {
const still = slide.querySelector('.still-preview');
const overlay = slide.querySelector('.play-overlay');
// Clear any still preview when switching projects
if (still) { still.style.display = 'none'; still.src = ''; }
document.getElementById('still-nav').style.display = 'none';
if (p.youtubeId) {
fr.src = 'https://www.youtube.com/embed/' + p.youtubeId + '?color=white&modestbranding=1&rel=0';
fr.style.display = 'block';
fr.setAttribute('data-loaded', '1');
cov.style.display = 'none';
if (overlay) { overlay.classList.remove('visible'); cov.removeAttribute('data-poster'); cov.onclick = null; }
} else if (p.vimeoId && p.cover) {
// Poster mode  -  show cover, load video on click
const vimeoSrc = 'https://player.vimeo.com/video/' + p.vimeoId + (p.vimeoHash ? '?h=' + p.vimeoHash + '&' : '?') + 'color=ff6600&title=0&byline=0&portrait=0&fullscreen=1&playsinline=0&autoplay=1' + (p.vimeoStart ? '#t=' + p.vimeoStart + 's' : '');
cov.src = p.cover;
cov.style.display = 'block';
cov.setAttribute('data-poster', 'true');
fr.src = '';
fr.style.display = 'none';
fr.removeAttribute('data-loaded');
if (overlay) overlay.classList.add('visible');
cov.onclick = function() {
fr.src = vimeoSrc;
fr.style.display = 'block';
fr.setAttribute('data-loaded', '1');
cov.style.display = 'none';
cov.removeAttribute('data-poster');
cov.onclick = null;
if (overlay) overlay.classList.remove('visible');
};
} else if (p.vimeoId) {
fr.src = 'https://player.vimeo.com/video/' + p.vimeoId + (p.vimeoHash ? '?h=' + p.vimeoHash + '&' : '?') + 'color=ff6600&title=0&byline=0&portrait=0&fullscreen=1&playsinline=0' + (p.vimeoStart ? '#t=' + p.vimeoStart + 's' : '');
fr.style.display = 'block';
fr.setAttribute('data-loaded', '1');
cov.style.display = 'none';
if (overlay) { overlay.classList.remove('visible'); cov.removeAttribute('data-poster'); cov.onclick = null; }
} else {
fr.src = '';
fr.style.display = 'none';
fr.removeAttribute('data-loaded');
const idx = projects.findIndex(proj => proj.id === p.id);
cov.src = p.cover || makeCoverSVG(idx);
cov.style.display = 'block';
if (overlay) { overlay.classList.remove('visible'); cov.removeAttribute('data-poster'); cov.onclick = null; }
}
}

function fadeInfo() {
const info = document.getElementById('proj-info');
info.style.opacity = '0';
info.style.transform = 'translateY(8px)';
setTimeout(() => {
updateInfo();
info.style.opacity = '1';
info.style.transform = 'translateY(0)';
}, 220);
}

function updateInfo() {
if (projects[cur].id === '_placeholder') { navTo(cur + 1); return; }
const p = projects[cur];
document.getElementById('proj-counter').textContent = (cur + 1) + '/' + projects.length;
document.getElementById('proj-cat').textContent = p.cat;
document.getElementById('proj-title').innerHTML = mixedCase(p.title);
document.getElementById('proj-meta').textContent = p.year + (p.dir ? '  -  ' + p.dir : '');
document.getElementById('proj-desc').innerHTML = p.desc;
// reset expanded state and check if clamping is needed
const descEl = document.getElementById('proj-desc');
const toggleEl = document.getElementById('desc-toggle');
const linkEl = document.getElementById('proj-readmore-link');
descEl.classList.remove('expanded');
if (linkEl) {
  if (p.readMoreLink) {
    linkEl.innerHTML = p.readMoreLink;
    linkEl.style.display = 'none';
  } else {
    linkEl.innerHTML = '';
    linkEl.style.display = 'none';
  }
}
toggleEl.classList.remove('visible');
toggleEl.textContent = 'Read more';
setTimeout(() => {
if (descEl.scrollHeight > descEl.clientHeight + 2 || (p.readMoreLink && linkEl && linkEl.innerHTML)) {
toggleEl.classList.add('visible');
}
}, 50);
document.getElementById('proj-dir').innerHTML = p.dir
? `<p class="detail-val">${p.dir}</p>`
: '<p class="detail-val" style="color:#9A9A9A"> - </p>';
document.getElementById('proj-tech').innerHTML = p.tech.map(t =>
`<p class="detail-val">${t}</p>`).join('') || '<p class="detail-val" style="color:#9A9A9A"> - </p>';
document.getElementById('proj-dist').innerHTML = p.dist && p.dist.length
? p.dist.map(d => `<p class="detail-val">${d}</p>`).join('')
: '<p class="detail-val" style="color:#9A9A9A"> - </p>';
document.getElementById('proj-awards').innerHTML = p.awards.map(a =>
`<p class="detail-val">${a}</p>`).join('');
const castCol = document.getElementById('proj-cast-col');
const castEl = document.getElementById('proj-cast');
if (p.cast && p.cast.length) {
const displayCast = p.cast.slice(0, 2);
castEl.innerHTML = displayCast.map(c => `<p class="detail-val">${c}</p>`).join('');
castCol.style.display = '';
} else {
castCol.style.display = 'none';
}
const testimonialEl = document.getElementById('proj-testimonial');
if (p.testimonial) {
testimonialEl.innerHTML = `<blockquote>"${p.testimonial.quote}"</blockquote><cite><a href="${p.testimonial.url}" target="_blank" rel="noopener noreferrer">${p.testimonial.attribution}  -  ${p.testimonial.company}</a></cite>`;
testimonialEl.style.display = 'block';
} else {
testimonialEl.innerHTML = '';
testimonialEl.style.display = 'none';
}
updateStills(p.id);
}

