let currentStillIndex = 0;
let currentStillImages = [];

function showStill(index) {
const activeSlide = document.querySelectorAll('.proj-slide')[cur];
if (!activeSlide) return;
const stillEl = activeSlide.querySelector('.still-preview');
const iframeEl = activeSlide.querySelector('.vframe');
const coverEl = activeSlide.querySelector('.slide-cover');
currentStillIndex = index;
stillEl.src = currentStillImages[index];
stillEl.style.display = 'block';
if (iframeEl) iframeEl.style.display = 'none';
if (coverEl) coverEl.style.display = 'none';
document.getElementById('still-nav').style.display = 'flex';
stillEl.onclick = () => hideStill();
}

function hideStill() {
const activeSlide = document.querySelectorAll('.proj-slide')[cur];
if (!activeSlide) return;
const stillEl = activeSlide.querySelector('.still-preview');
const iframeEl = activeSlide.querySelector('.vframe');
const coverEl = activeSlide.querySelector('.slide-cover');
stillEl.style.display = 'none';
stillEl.src = '';
if (iframeEl) iframeEl.style.display = iframeEl.getAttribute('data-loaded') ? 'block' : 'none';
if (coverEl) coverEl.style.display = iframeEl && iframeEl.getAttribute('data-loaded') ? 'none' : 'block';
document.getElementById('still-nav').style.display = 'none';
}

function updateStills(id) {
const section = document.getElementById('stills-section');
const strip = document.getElementById('thumb-strip');
const imgs = STILLS[id];
document.getElementById('still-nav').style.display = 'none';
currentStillImages = [];
if (imgs) {
currentStillImages = imgs.map(src => typeof src === 'object' ? src.src : src);
strip.innerHTML = currentStillImages.map((src, i) =>
`<div class="thumb-item"><img src="${src}" alt="Glenn Hanns ACS Director of Photography Sydney" loading="lazy" /></div>`
).join('');
section.style.display = 'block';
strip.querySelectorAll('.thumb-item img').forEach((img, i) => {
img.style.cursor = 'zoom-in';
img.addEventListener('click', () => showStill(i));
});
} else {
strip.innerHTML = '';
section.style.display = 'none';
}
}

document.addEventListener('DOMContentLoaded', () => {
const hash = window.location.hash.replace('#','');
if (hash) {
    const idx = projects.findIndex(p => p.id === hash);
    if (idx > 0) setTimeout(() => navTo(idx), 100);
}
document.getElementById('still-prev').addEventListener('click', () => {
const newIdx = (currentStillIndex - 1 + currentStillImages.length) % currentStillImages.length;
showStill(newIdx);
});
document.getElementById('still-next').addEventListener('click', () => {
const newIdx = (currentStillIndex + 1) % currentStillImages.length;
showStill(newIdx);
});
});

function updateNav() {
document.getElementById('btn-prev').style.opacity = cur === 0 ? '0.25' : '1';
document.getElementById('btn-next').style.opacity = cur === projects.length - 1 ? '0.25' : '1';
}

function navTo(n) {
if (n < 0 || n >= projects.length) return;
const slide = document.querySelectorAll('.proj-slide')[n];
if (slide) slide.scrollIntoView({behavior: 'smooth', block: 'nearest', inline: 'center'});
}

function toggleDesc() {
const descEl = document.getElementById('proj-desc');
const toggleEl = document.getElementById('desc-toggle');
const linkEl = document.getElementById('proj-readmore-link');
const expanded = descEl.classList.toggle('expanded');
toggleEl.textContent = expanded ? 'Read less' : 'Read more';
if (linkEl && linkEl.innerHTML) linkEl.style.display = expanded ? 'block' : 'none';
}

buildSwiper();
updateInfo();
updateNav();

function submitContactForm() {
    const name    = document.getElementById('cf-name').value.trim();
    const email   = document.getElementById('cf-email').value.trim();
    const subject = document.getElementById('cf-subject').value;
    const message = document.getElementById('cf-message').value.trim();
    if (!name || !email || !subject || !message) {
        alert('Please fill in all fields before sending.');
        return;
    }
    const mailto = `mailto:glenn@glennhanns.com?subject=${encodeURIComponent(subject + '  -  ' + name)}&body=${encodeURIComponent('Name: ' + name + '\nEmail: ' + email + '\n\n' + message)}`;
    window.location.href = mailto;
    document.getElementById('contactForm').style.display = 'none';
    document.getElementById('contactSuccess').style.display = 'block';
}
document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape') document.getElementById('contactModal').classList.remove('open');
});